export type GetDownloadsParams = {
    /**
     * Filter by package ID
     */
    pkgId: string | null;
    /**
     * Filter by version
     */
    version: string | null;
    /**
     * Start of time range (RFC 3339)
     */
    after: string | null;
    /**
     * End of time range (RFC 3339)
     */
    before: string | null;
};
